package day2;
import com.microsoft.playwright.*;
import com.microsoft.playwright.options.*;
import static com.microsoft.playwright.assertions.PlaywrightAssertions.assertThat;
import java.util.*;

public class CodegenDemo1 {

    public static void main(String[] args) {
        try (Playwright playwright = Playwright.create()) {
            Browser browser = playwright.chromium().launch(new BrowserType.LaunchOptions()
                    .setHeadless(false));
            BrowserContext context = browser.newContext();
            Page page = context.newPage();
            page.navigate("https://playwright.dev/java/");
            page.getByRole(AriaRole.LINK, new Page.GetByRoleOptions().setName("Docs")).click();
            page.getByRole(AriaRole.TAB, new Page.GetByRoleOptions().setName("pom.xml")).click();
            page.getByRole(AriaRole.TAB, new Page.GetByRoleOptions().setName("pom.xml")).click();
            page.getByRole(AriaRole.HEADING, new Page.GetByRoleOptions().setName("System requirementsDirect")).click();
            assertThat(page.getByRole(AriaRole.LINK, new Page.GetByRoleOptions().setName("GitHub repository"))).isVisible();
            assertThat(page.locator("#first-script")).containsText("First script");
            page.getByRole(AriaRole.LINK, new Page.GetByRoleOptions().setName("Write tests using web first")).click();
            page.getByText("Take a look at the example").click();
            page.getByRole(AriaRole.LINK, new Page.GetByRoleOptions().setName("Locators")).nth(4).click();
            page.getByRole(AriaRole.LINK, new Page.GetByRoleOptions().setName("Docs")).click();
            page.getByRole(AriaRole.LINK, new Page.GetByRoleOptions().setName("API").setExact(true)).click();
            page.getByRole(AriaRole.LINK, new Page.GetByRoleOptions().setName("close").setExact(true)).click();
            assertThat(page.getByRole(AriaRole.ARTICLE)).matchesAriaSnapshot("- heading \"Playwright\" [level=1]\n- paragraph: \"Playwright module provides a method to launch a browser instance. The following is a typical example of using Playwright to drive automation:\"\n- code: \"import com.microsoft.playwright.*; public class Example { public static void main(String[] args) { try (Playwright playwright = Playwright.create()) { BrowserType chromium = playwright.chromium(); Browser browser = chromium.launch(); Page page = browser.newPage(); page.navigate(\\\"http://example.com\\\"); // other actions... browser.close(); } } }\"\n- button \"Copy code to clipboard\"\n- separator\n- heading \"MethodsDirect link to Methods\" [level=2]:\n  - text: \"\"\n  - link \"Direct link to Methods\":\n    - /url: \"#methods\"\n    - text: \"\"\n- heading \"closeDirect link to close\" [level=3]:\n  - text: \"\"\n  - link \"Direct link to close\":\n    - /url: \"#playwright-close\"\n    - text: \"\"\n- text: \"Added in: v1.9\"\n- paragraph: Terminates this instance of Playwright, will also close all created browsers if they are still running.\n- paragraph:\n  - strong: Usage\n- code: Playwright.close();\n- button \"Copy code to clipboard\"\n- separator\n- heading \"createDirect link to create\" [level=3]:\n  - text: \"\"\n  - link \"Direct link to create\":\n    - /url: \"#playwright-create\"\n    - text: \"\"\n- text: \"/Added in: v1\\\\.\\\\d+/\"\n- paragraph:\n  - text: Launches new Playwright driver process and connects to it.\n  - link \"Playwright.close()\":\n    - /url: /java/docs/api/class-playwright#playwright-close\n  - text: should be called when the instance is no longer needed.\n- code: Playwright playwright = Playwright.create(); Browser browser = playwright.webkit().launch(); Page page = browser.newPage(); page.navigate(\"https://www.w3.org/\"); playwright.close();\n- button \"Copy code to clipboard\"\n- paragraph:\n  - strong: Usage\n- code: Playwright.create(); Playwright.create(options);\n- button \"Copy code to clipboard\"\n- paragraph:\n  - strong: Arguments\n- list:\n  - listitem:\n    - code: options\n    - code: Playwright.CreateOptions\n    - emphasis: (optional)\n    - list:\n      - listitem:\n        - paragraph:\n          - code: setEnv\n          - link \"Map\":\n            - /url: https://docs.oracle.com/javase/8/docs/api/java/util/Map.html\n          - text: <\n          - link \"String\":\n            - /url: https://docs.oracle.com/javase/8/docs/api/java/lang/String.html\n          - text: \",\"\n          - link \"String\":\n            - /url: https://docs.oracle.com/javase/8/docs/api/java/lang/String.html\n          - text: \">\"\n          - emphasis: (optional)\n          - text: \"/Added in: v1\\\\.\\\\d+/\"\n          - link \"#\":\n            - /url: \"#playwright-create-option-env\"\n        - paragraph: Additional environment variables that will be passed to the driver process. By default driver process inherits environment variables of the Playwright process.\n- paragraph:\n  - strong: Returns\n- list:\n  - listitem:\n    - link \"Playwright\":\n      - /url: /java/docs/api/class-playwright\n    - link \"#\":\n      - /url: \"#playwright-create-return\"\n- separator\n- heading \"PropertiesDirect link to Properties\" [level=2]:\n  - text: \"\"\n  - link \"Direct link to Properties\":\n    - /url: \"#properties\"\n    - text: \"\"\n- heading \"chromium()Direct link to chromium()\" [level=3]:\n  - text: \"\"\n  - link \"Direct link to chromium()\":\n    - /url: \"#playwright-chromium\"\n    - text: \"\"\n- text: Added before v1.9\n- paragraph:\n  - text: This object can be used to launch or connect to Chromium, returning instances of\n  - link \"Browser\":\n    - /url: /java/docs/api/class-browser\n  - text: .\n- paragraph:\n  - strong: Usage\n- code: Playwright.chromium()\n- button \"Copy code to clipboard\"\n- paragraph:\n  - strong: Returns\n- list:\n  - listitem:\n    - link \"BrowserType\":\n      - /url: /java/docs/api/class-browsertype\n- separator\n- heading \"firefox()Direct link to firefox()\" [level=3]:\n  - text: \"\"\n  - link \"Direct link to firefox()\":\n    - /url: \"#playwright-firefox\"\n    - text: \"\"\n- text: Added before v1.9\n- paragraph:\n  - text: This object can be used to launch or connect to Firefox, returning instances of\n  - link \"Browser\":\n    - /url: /java/docs/api/class-browser\n  - text: .\n- paragraph:\n  - strong: Usage\n- code: Playwright.firefox()\n- button \"Copy code to clipboard\"\n- paragraph:\n  - strong: Returns\n- list:\n  - listitem:\n    - link \"BrowserType\":\n      - /url: /java/docs/api/class-browsertype\n- separator\n- heading \"request()Direct link to request()\" [level=3]:\n  - text: \"\"\n  - link \"Direct link to request()\":\n    - /url: \"#playwright-request\"\n    - text: \"\"\n- text: \"/Added in: v1\\\\.\\\\d+/\"\n- paragraph: Exposes API that can be used for the Web API testing.\n- paragraph:\n  - strong: Usage\n- code: Playwright.request()\n- button \"Copy code to clipboard\"\n- paragraph:\n  - strong: Returns\n- list:\n  - listitem:\n    - link \"APIRequest\":\n      - /url: /java/docs/api/class-apirequest\n- separator\n- heading \"selectors()Direct link to selectors()\" [level=3]:\n  - text: \"\"\n  - link \"Direct link to selectors()\":\n    - /url: \"#playwright-selectors\"\n    - text: \"\"\n- text: Added before v1.9\n- paragraph:\n  - text: Selectors can be used to install custom selector engines. See\n  - link \"extensibility\":\n    - /url: /java/docs/extensibility\n  - text: for more information.\n- paragraph:\n  - strong: Usage\n- code: Playwright.selectors()\n- button \"Copy code to clipboard\"\n- paragraph:\n  - strong: Returns\n- list:\n  - listitem:\n    - link \"Selectors\":\n      - /url: /java/docs/api/class-selectors\n- separator\n- heading \"webkit()Direct link to webkit()\" [level=3]:\n  - text: \"\"\n  - link \"Direct link to webkit()\":\n    - /url: \"#playwright-webkit\"\n    - text: \"\"\n- text: Added before v1.9\n- paragraph:\n  - text: This object can be used to launch or connect to WebKit, returning instances of\n  - link \"Browser\":\n    - /url: /java/docs/api/class-browser\n  - text: .\n- paragraph:\n  - strong: Usage\n- code: Playwright.webkit()\n- button \"Copy code to clipboard\"\n- paragraph:\n  - strong: Returns\n- list:\n  - listitem:\n    - link \"BrowserType\":\n      - /url: /java/docs/api/class-browsertype");
            assertThat(page.getByRole(AriaRole.ARTICLE)).matchesAriaSnapshot("- code: Playwright.close();");
        }
    }
}
